window.__QUIZ_DATA__=[{"id":"theory>Geography>2019>1>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Outline five factors which an industrialist will consider when locating a fruit canning industry.","images":[],"marking_scheme":"i. Availability of labour   ii. Availability of capital  iii. Nearness to source of power  iv. Adequate transport network.  v. Proximity to source of raw materials.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2019>1>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Explain five benefits derived from the concentration of manufacturing industries in urban centres.","images":[],"marking_scheme":"- It creates more employment.  - It increases state and local government revenue.  - It brings development of manpower.  - It brings civilization.  - It also brings new technologies.  - Provision of goods and services.  - Other sectors of the economy will be stimulated.","marks":"10","difficulty":"2"},{"id":"theory>Geography>2019>2>a>i","subject":"Geography","year":"2019","type":"Theory","sub_label":"i","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Table 1 below shows the population distribution and land area of five states of country B in the year 2010. Use the data to answer this question  StatePopulation (in million)Total land area (km2U  V  W  X  Y3.2  5.4  7.4  6.5  4.2140,000  98,000  35,000  120,000  86,000    Calculate the total population.","images":[],"marking_scheme":"Total population = 3.2 + 5.4 + 7.4 + 6.5 + 4.2  \u21d2 26.7 million","marks":"4","difficulty":"1"},{"id":"theory>Geography>2019>2>a>ii","subject":"Geography","year":"2019","type":"Theory","sub_label":"ii","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Table 1 below shows the population distribution and land area of five states of country B in the year 2010. Use the data to answer this question  StatePopulation (in million)Total land area (km2U  V  W  X  Y3.2  5.4  7.4  6.5  4.2140,000  98,000  35,000  120,000  86,000  Calculate the total land area.","images":[],"marking_scheme":"Total land area = 140,000 + 98,000 + 35,000 + 120,000 + 86,000 = 479,000 km2","marks":"4","difficulty":"1"},{"id":"theory>Geography>2019>2>a>iii","subject":"Geography","year":"2019","type":"Theory","sub_label":"iii","group":"FINAL","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"The Table 1 below shows the population distribution and land area of five states of country B in the year 2010. Use the data to answer this question  StatePopulation (in million)Total land area (km2U  V  W  X  Y3.2  5.4  7.4  6.5  4.2140,000  98,000  35,000  120,000  86,000  Calculate the population density of country B.","images":[],"marking_scheme":"PopulationdensityofcountryB=Total population of BLand area of B  =26,700,000479,000 = 557.41 person/km2","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>2>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Explain four factors that influence the distribution of world human population.","images":[],"marking_scheme":"- Agriculture: Area with well developed farming of crops or animals are often densely populated.  - Secondary industry: Those areas in which manufacturing has developed tend to be densely populated. It is worth nothing that even in old industrial areas in which manufacturing has declined or even closed, population densities may remain high.  - Accessibility: Areas with well developed transport infrastructure and links through road, rail, shipping, canals and air are likely to be more densely populated than areas which are poorly connected.  - Conflict: Wars and conflicts can lend to significant movements of population and a simultaneous decrease in density in some areas while others may increase.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>2>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Outline three factors that cause increase in world human population.","images":[],"marking_scheme":"- Availability of birth control/Availability of family planning education/use of birth control.  - Health care/access to health care/ medical technology/ability to fight or prevent diseases.  - Culture-social norms, values and traditions (the use of contraception )  - the age at which marriage is socially acceptable.  - Religious belief on family planning.  - Gender equality","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>3>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write a geographical account of road transportation under the heading:    three advantages.","images":[],"marking_scheme":"- It provides door to door services i.e it can get to anywhere within the country.  - It makes goods available where they are scarce.  - Road facilitate the movement of people within a short distance.  - It feeds water, rail and air transportation.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>3>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write a geographical account of road transportation under the heading:  three disadvantages","images":[],"marking_scheme":"- Roads are very expensive to construct and maintain.  - Roads are difficult to construct, especially in highlands and swampy areas.  - Amount of goods and passengers carried by roads is limited.  - They are more prone to damage, especially washouts caused by heavy rain.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>3>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"Write a geographical account of road transportation under the heading:  four contributions to development.","images":[],"marking_scheme":"- Agriculture raw materials such as cocoa, cotton, palm produce, timber e.t.c are mostly conveyed by road to the processing factories scattered all over the country.  - It leads to increased agricultural mineral and industrial production.  - It aids the movement of people or labour and capital.  - It gives rise to employment opportunities.  - It links areas of production with areas of corm smp in a country.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2019>4>a>i","subject":"Geography","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw a sketch map of Nigeria.  On the map, show and name:    one cocoa growing belt.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>4>a>ii","subject":"Geography","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw a sketch map of Nigeria.  On the map, show and name:  one groundnut growing belt.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>4>a>iii","subject":"Geography","year":"2019","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Draw a sketch map of Nigeria.  On the map, show and name:  one town in 4(a)(i).","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>4>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Describe three physical conditions necessary for the cultivation of groundnut.","images":[],"marking_scheme":"- Groundnut requires a wide plain for easy cultivation.  - It requires a rainfall of 50 - 100cm per annum.  - It requires a loose sandy soil which make planting and harvestation easy.  - It required long dry season for the drying of fruits.","marks":"4","difficulty":"3"},{"id":"theory>Geography>2019>4>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Explain four ways in which groundnut cultivation has contributed to the economy of Nigeria.","images":[],"marking_scheme":"- It aids the boosting of the GNDP (Gross national domestic product) of the country.  - It creates employment opportunities for the citizens.  - It helps in creating the availability of oil used for domestic purposes.  - It is a source of income to the populates as it boost the per capital income of the populates.  - It is a source of foreign exchange.  - It provides market for industrial goods.","marks":"4","difficulty":"3"},{"id":"theory>Geography>2019>5>a>i","subject":"Geography","year":"2019","type":"Theory","sub_label":"i","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"Draw an outline map of Nigeria.  On the map, locate and name:    one national park in the north that is important for tourism.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>5>a>ii","subject":"Geography","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"Draw an outline map of Nigeria.  On the map, locate and name:  one national park in the south that is important for tourism.","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>5>a>iii","subject":"Geography","year":"2019","type":"Theory","sub_label":"iii","group":"","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"Draw an outline map of Nigeria.  On the map, locate and name:  Calabar town","images":["data:image/png;base64,"],"marking_scheme":"","marks":"4","difficulty":"1"},{"id":"theory>Geography>2019>5>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"List four factors that retard tourism development in Nigeria.","images":[],"marking_scheme":"- Inadequate funding: The tourism industry is poorly funded and it retards the development of tourist center in Nigeria.  - Lack of private investment in Nigeria retards the development of tourist center.  - Inadequate personnel  - Poor publicity: Lack of publicity for publishing the scenery wildlife and culture attractions to visitors is a problem to Nigeria.  - Absence of tourism boards","marks":"4","difficulty":"1"},{"id":"theory>Geography>2019>5>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : TOURISM","question":"List three ways tourism can be promoted in Nigeria.","images":[],"marking_scheme":"- Increase in budgeting provision: There should be increase and release of budgeting provision by government for tourism development.  - Engagement of private sector: The government should encourage and embrace the private sector in order to drive the tourism development programmes.  - Pursuance of aggressive marketing strategies have to be put in place to promote tourism assets locally and internationally.  - Launching of tourism development trust: The government should launch tourism development funds.  This funds will also go a long way to ensure adequate provision of capital for tourism development in the country.","marks":"4","difficulty":"1"},{"id":"theory>Geography>2019>6>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Write a geographical account of mining in Nigeria under this heading:    four mineral deposits.","images":[],"marking_scheme":"- Tin  - Gold   - Coal  - Iron ore  - Limestone  - Petroleum","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>6>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Write a geographical account of mining in Nigeria under this heading:  one town that is important for the mining of each of the minerals in 6(a).","images":[],"marking_scheme":"Tin - Jos  Gold - Ilesa and Sokoto  Coal - Enugu  Iron ore - Lokoja, Enugu  Limestone - Sokoto, Ewekoro  Petroleum - Warri, Port Harcourt","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>6>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Write a geographical account of mining in Nigeria under this heading:  three benefits of mining in Nigeria.","images":[],"marking_scheme":"- It is a source of foreign exchange  - Employment opportunities  - It serves as raw materials for many industries.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>6>d","subject":"Geography","year":"2019","type":"Theory","sub_label":"d","group":"CLOSENESS","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"Write a geographical account of mining in Nigeria under this heading:  three negative effects of mining on the environment of mining areas.","images":[],"marking_scheme":"- Oil spillage  - Health hazard which causes lung cancer  - The natural gas and oil occur together which is highly flammable.  - Environmental pollution","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>7>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1 : 50,000 and answer this question    On the graph paper provided, draw an annotated cross section from the road junction at AFIENYA to the road junction at Dawhenya (Darwenya).","images":[],"marking_scheme":"Graph work from the map provided.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2019>7>b>i","subject":"Geography","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1 : 50,000 and answer this question  In this answer booklet, describe:    three relief characteristics of the mapped area.","images":[],"marking_scheme":"- Generally, the place is low lying area  - This is a ridge that is the shai hills in the northern part of the map ranging from 250ft to 90ft  - The general area is underlying and almost flat.","marks":"6","difficulty":"3"},{"id":"theory>Geography>2019>7>b>ii","subject":"Geography","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Study the map extract provided on a scale of 1 : 50,000 and answer this question  In this answer booklet, describe:  three drainage characteristics of the mapped area.","images":[],"marking_scheme":"- The river exhibit dendritic pattern.  - River dekyider is demanded around the salt pond.  - River ohudor flows towards the south","marks":"3","difficulty":"3"},{"id":"theory>Geography>2019>7>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Study the map extract provided on a scale of 1 : 50,000 and answer this question  With evidence from the map, identify two functions of Doryum settlement.","images":[],"marking_scheme":"- Administrative function due to the presence of schools, police and offices.  - Religions function due to the presence of church.","marks":"3","difficulty":"2"},{"id":"theory>Geography>2019>8>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"The Table X below shows the number of farm units in three villages of Oju District in the year 2010.  Use the data in Table X to answer this question  Table X  VillageNumber of farm unitsA  B  C81  100  64    Using the map of Oju District provided and a radius of 1cm to represent 3 farm units, construct proportional circles to represent the data.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"ForA=813=27cm  ForB=1003=33.3cm  ForC=643=21.33cm","marks":"12","difficulty":"3"},{"id":"theory>Geography>2019>8>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : STATISTICAL MAPS AND DIAGRAMS","question":"State two disadvantages of proportional circles.","images":[],"marking_scheme":"- Do not easily reveal exact values.  - Many pie charts may be needed to show changes over time.  - Fact to reveal key assumptions causes, effects or patterns.  - Be easily manipulated to yield false impressions.","marks":"8","difficulty":"1"},{"id":"theory>Geography>2019>9>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe chemically formed sedimentary rocks under this heading:    mode of formation.","images":[],"marking_scheme":"Chemically formed sedimentary rock are formed when chemical sediments accumulated over a long period of time. These sediments then undergo further processes to form rock.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>9>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe chemically formed sedimentary rocks under this heading:  three examples.","images":[],"marking_scheme":"- Potash  - Nitrate  - Dolomite  - Gypsum  - Sodium chloride (Common salt)","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>9>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Describe chemically formed sedimentary rocks under this heading:  four importance.","images":[],"marking_scheme":"- They serve as a source of minerals such as halite i.e common salt.  - They produce limestone used in producing element.  - They houses fossil records.  - They are useful as feed additives.  - Sources of plant nutrients.  - Useful as liming materials.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2019>10>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"What is a lake?","images":[],"marking_scheme":"A lake is a land locked body of slow-flowing water.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2019>10>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Describe the formation of lakes by wind erosion.","images":[],"marking_scheme":"These are lakes formed where wind deflation erode and result into formation of depression in desert. If such depressions are small and shallow pan lakes may form. But sometimes depression goes deeper to expose water table which result into formation of oasis lakes like in Qattara Depression in Egypt.","marks":"8","difficulty":"3"},{"id":"theory>Geography>2019>10>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"Identify three benefits of lakes to man.","images":[],"marking_scheme":"- It provides water and food for human use.  - It helps in water pollination purification to support ecosystems.  - It serves as tourist center.  - It provides employment opportunities.  - Source of revenue for local and public government bodies.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2019>11>a>i","subject":"Geography","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"Highlight four characteristics of Time Zone.","images":[],"marking_scheme":"- Each time zone differ by 15\u00b0 in longitude   - The reference point is the G. M. T.  - It is divided within 24 time zone.  - It maintains the essential time for their respective zones.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>11>a>ii","subject":"Geography","year":"2019","type":"Theory","sub_label":"ii","group":"","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"Highlight four characteristics of International Dateline.","images":[],"marking_scheme":"- Data change by 24 hrs when it is crossed.  - The 180 degree meridian represent for the original of a data line.  - Travelers going to the east gains one day which does going to the west losses one day.  - It is not a straight line.","marks":"4","difficulty":"2"},{"id":"theory>Geography>2019>11>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"FINAL","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : GEOGRAPHIC INFORMATION SYSTEM (GIS)","question":"If two towns A and B are located on different time zones and the time in town A is 9.00am while the time in town B is 6.00pm the same day, calculate the longitude of town B if the longitude of town A is 30\u00b0W.","images":[],"marking_scheme":"Time difference = 18:00 hrs - 9:00hr  \u21d2 9:00hrs    Recall, 1 hr = 15\u00b0  Longitude = 9 \u00d7 15 = 185\u00b0  Longitude of town B = (135\u00b0 - 30\u00b0)  \u21d2 95\u00b0S","marks":"12","difficulty":"3"},{"id":"theory>Geography>2019>12>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"With the aid of diagrams, describe the mode of formation of this feature:  stack.","images":["data:image/png;base64,"],"marking_scheme":"Mode of Formation  It is formed by wave erosion. There is presence of a headland. Wave erosion attacks headland at both sides. Two caves formed on opposite sides of the headland. Further erosion of caves produces an arch when caves joined up, roof of arch collapses and the seaward portion of the headland remains as a pillar known as stock.","marks":"10","difficulty":"3"},{"id":"theory>Geography>2019>12>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : TECTONIC PROCESSES","question":"With the aid of diagrams, describe the mode of formation of this feature:  fold mountain.","images":["data:image/png;base64,"],"marking_scheme":"Mode of Formation  It is formed from the folding of the earth crust when sedimentary rocks thickness deposit accumulate along the edges of continents, the plates and the continents riding on then collide, the accumulated layers of rock crumple and fold like a table cloth that is pushed across a table","marks":"10","difficulty":"3"},{"id":"theory>Geography>2019>13>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"With the aid of a labelled diagram, describe the weather instrument used to measure the amount of rainfall.","images":["data:image/png;base64,"],"marking_scheme":"The instrument used to measure the amount of rainfall is the rain gauge.    Rain gauge consists of a metal funnel that leads to a glass bottle enclosed within a copper cylinder.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2019>13>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"State three precautions which must be taken when using the instrument described in 7(a).","images":[],"marking_scheme":"- The gauge is usually erected high above the ground (30cm) to avoid rain splashing.  - The gauge is sited for away from building and tall trees that might shelter it.  - The rain gauge must be examined everyday and daily records taken.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>13>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Explain how the instrument described in 7(a) is used to obtain total annual rainfall.","images":[],"marking_scheme":"* The records is taken by removing the funnel and the contents of the glass bottle are emptied into the measuring cylinder. The water level of the measuring cylinder in millimetres is read at eye level. Annual rainfall can be obtain by adding the total rainfall for the year i.e from January - December.","marks":"6","difficulty":"2"},{"id":"theory>Geography>2019>14>a","subject":"Geography","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Define food chain.","images":[],"marking_scheme":"Food chain can be defined as a series of network in an ecosystem. It shows how the organisms are related with each other by the food they eat.","marks":"6","difficulty":"1"},{"id":"theory>Geography>2019>14>b","subject":"Geography","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Describe the energy flow within a terrestrial ecosystem.","images":[],"marking_scheme":"Energy flow within a terrestrial ecosystem: Energy from the sun is received by the producer which are plants, produce their food and hence when consumed by the consumer energy is passed, when the consume which are animals feed on the plant, they absorb energy, those energy is used for body development and when consumed by a higher animal, the energy is also utilised and finally when the organism dies, decomposers act on the organism and some energy is used and stored. Energy generally reduces down the food chain.","marks":"8","difficulty":"2"},{"id":"theory>Geography>2019>14>c","subject":"Geography","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"Highlight three ways by which nitrogen cycle is maintained in the terrestrial ecosystem.","images":[],"marking_scheme":"i. Ammonication which is part of decaying process.  ii. Dentrification  iii. Plants absorb nutrients from the soil into their roots.  iv. Animals get nitrogen from plant consumed","marks":"6","difficulty":"2"}];